SELECT target_name
FROM genomic_targets
WHERE species = 'Human';

SELECT target_name
FROM genomic_targets
ORDER BY target_name;

SELECT method
FROM gene_editing_data
WHERE experiment_id = 1;

SELECT COUNT(upload_id) AS upload_count
FROM data_upload_history
WHERE researcher_id = 1;

SELECT COUNT(target_id) AS number_of_targets
FROM genomic_targets
WHERE reporter_expression >= 25 AND species = 'Human';

SELECT AVG(percentage_germline_transmitting_adults) AS avg_percentage
FROM gene_editing_data
WHERE method = 'CRISPR';

SELECT number_germline_transmitting_adults
FROM gene_editing_data
WHERE data_id = 0;

SELECT researcher_name
FROM researchers
WHERE researcher_id IN (
  SELECT created_by
  FROM genomic_targets
);
